const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  // ✅ AQI Label function
  const getAQILabel = (value) => {
    const v = Number(value);

    if (v === 1) return "Good";
    if (v === 2) return "Moderate";
    if (v === 3) return "Unhealthy (Sensitive)";
    if (v === 4) return "Unhealthy";
    if (v === 5) return "Very Unhealthy";
    if (v === 6) return "Hazardous";

    return "Unknown";
  };

  // ✅ AQI Color function
  const getAQIColor = (value) => {
    const v = Number(value);

    if (v === 1) return "#00e400";
    if (v === 2) return "#ffff00";
    if (v === 3) return "#ff7e00";
    if (v === 4) return "#ff0000";
    if (v === 5) return "#8f3f97";
    if (v === 6) return "#7e0023";

    return "#ccc";
  };

  // ✅ Simple check (fresher-friendly)
  const hasAQI = aqi;

  return (
    <div className="card">
      <h2>{city}</h2>

      <img src={icon} alt="weather icon" />

      <p>Temperature: {temperature}</p>
      <p>Feels Like: {feelsLike}</p>
      <p>Condition: {condition}</p>
      <p>Wind: {wind}</p>
      <p>Humidity: {humidity}</p>

      {/* 🔥 AQI BOX */}
      <div
        style={{
          backgroundColor: hasAQI ? getAQIColor(aqi) : "#ccc",
          padding: "10px",
          borderRadius: "8px",
          marginTop: "10px",
          color: "#000",
          fontWeight: "bold"
        }}
      >
        AQI: {hasAQI ? aqi : "N/A"}{" "}
        {hasAQI ? `— ${getAQILabel(aqi)}` : ""}
      </div>
    </div>
  );
};

export default WeatherCard;
